from pathlib import Path

name='Are aligned neural networks adversarially aligned'
page_id='1a084951-e962-80f5-abe0-f41c49402668'
obj=json.loads(Path('notes/_notion_raw/'+name+'.json').read_text(encoding='utf-8'))
blocks=obj['blocks']

def block_value(entry):
    if not isinstance(entry, dict):
        return {}
    v=entry.get('value',{})
    if isinstance(v,dict) and isinstance(v.get('value'),dict):
        return v['value']
    if isinstance(v,dict):
        return v
    return {}

def rich_plain(parts):
    if not parts:
        return ''
    out=[]
    for seg in parts:
        if isinstance(seg,list) and seg:
            t=seg[0]
            if isinstance(t,str):
                out.append(t)
    return ''.join(out).strip()

def title(v):
    return rich_plain((v.get('properties') or {}).get('title'))

def source(v):
    fmt=v.get('format') or {}
    if isinstance(fmt.get('display_source'),str):
        return fmt['display_source']
    return ''

lines=[]
visited=set()
img_idx=0

def walk(bid,depth=0):
    global img_idx
    if bid in visited:
        return
    visited.add(bid)
    v=block_value(blocks.get(bid,{}))
    t=v.get('type','unknown')
    pre='  '*depth
    if t=='page':
        lines.append(f"{pre}- [page] {title(v) or bid}")
    elif t=='header':
        lines.append(f"{pre}# {title(v)}")
    elif t=='sub_header':
        lines.append(f"{pre}## {title(v)}")
    elif t=='sub_sub_header':
        lines.append(f"{pre}### {title(v)}")
    elif t=='numbered_list':
        lines.append(f"{pre}1. {title(v)}")
    elif t=='bulleted_list':
        lines.append(f"{pre}- {title(v)}")
    elif t=='quote':
        lines.append(f"{pre}> {title(v)}")
    elif t=='text':
        tx=title(v)
        if tx:
            lines.append(f"{pre}{tx}")
    elif t=='image':
        img_idx +=1
        lines.append(f"{pre}- [image] {source(v)} | image_index={img_idx} | block_id={bid}")
    else:
        lines.append(f"{pre}- [type:{t}] {title(v) or ''}")
    for cid in v.get('content') or []:
        if isinstance(cid,str):
            walk(cid,depth+1)

walk(page_id)
out=Path('notes/_notion_raw/'+name+'.ordered.md')
out.write_text('\n'.join(lines),encoding='utf-8')
print(str(out).replace('\\','/'))
